import { FastifyInstance } from 'fastify';

export async function iterationRoutes(fastify: FastifyInstance) {
  // 获取迭代列表
  fastify.get('/api/iterations', async (request, reply) => {
    const { page = 1, limit = 20, status } = request.query as any;

    const iterations = await fastify.iterationService.list({
      page,
      limit,
      status
    });

    return iterations;
  });

  // 获取迭代详情
  fastify.get('/api/iterations/:id', async (request, reply) => {
    const { id } = request.params as { id: string };
    const iteration = await fastify.iterationService.findById(id);

    if (!iteration) {
      return reply.status(404).send({ error: 'Not found' });
    }

    return iteration;
  });

  // 获取当前运行迭代
  fastify.get('/api/iterations/current', async (request, reply) => {
    const current = await fastify.iterationService.getCurrent();
    return current || { status: 'idle' };
  });
}
```

##### 2.2 完善 WebSocket 事件

**文件**: `dashboard/server/services/realtime.service.ts`
```typescript
export class RealtimeService {
  private server: WebSocketServer;
  private subscriptions: Map<string, Set<WebSocket>>;

  constructor(server: WebSocketServer) {
    this.server = server;
    this.subscriptions = new Map();
  }

  // 订阅项目事件
  subscribe(client: WebSocket, projectId: string) {
    if (!this.subscriptions.has(projectId)) {
      this.subscriptions.set(projectId, new Set());
    }
    this.subscriptions.get(projectId)!.add(client);
  }

  // 广播迭代状态变更
  broadcastIterationStatus(iteration: Iteration) {
    this.broadcast('iteration.status_changed', {
      id: iteration.id,
      status: iteration.status,
      progress: iteration.progress
    });
  }

  // 广播 Agent 进度
  broadcastAgentProgress(agent: string, progress: number, message: string) {
    this.broadcast('agent.progress', {
      agent,
      progress,
      message,
      timestamp: new Date()
    });
  }

  // 广播实时日志
  broadcastLog(level: string, message: string) {
    this.broadcast('log.line', {
      level,
      message,
      timestamp: new Date()
    });
  }

  private broadcast(event: string, data: any) {
    const payload = JSON.stringify({ event, data });

    for (const [project, clients] of this.subscriptions) {
      for (const client of clients) {
        if (client.readyState === WebSocket.OPEN) {
          client.send(payload);
        }
      }
    }
  }
}
```

