export class AutoIterationEngine {
  private realtimeService?: RealtimeService;

  async start() {
    // 获取 Dashboard 服务
    try {
      const { getServices } = await import('./dashboard/server');
      const services = getServices();
      this.realtimeService = services.realtimeService;
    } catch (e) {
      console.log('Dashboard not available');
    }

    // 迭代开始时通知
    if (this.realtimeService) {
      this.realtimeService.broadcastIterationStatus({
        id: this.iterationId,
        status: 'running',
        progress: 0
      });
    }

    // 执行产品经理 Agent
    await this.executeAgent('product-manager', async (pm) => {
      const requirement = await pm.analyzeAndCollect();

      // 实时推送进度
      if (this.realtimeService) {
        this.realtimeService.broadcastAgentProgress(
          'product-manager',
          100,
          '需求分析完成'
        );
      }

      return requirement;
    });
