```typescript
export class Orchestrator {
  private projects = new Map<string, ProjectContext>();
  private scheduler: TaskScheduler;

  async createProject(config: ProjectConfig): Promise<string> {
    const projectId = generateId();
    const project = new ProjectContext(projectId, config);

    this.projects.set(projectId, project);

    // 通知 Dashboard
    this.realtimeService.broadcast('project.created', {
      id: projectId,
      name: config.name
    });

    return projectId;
  }

  async executeTask(projectId: string, task: Task) {
    const project = this.projects.get(projectId);
    if (!project) {
      throw new Error(`Project ${projectId} not found`);
    }

    return this.scheduler.schedule(project, task);
  }

  async getProjectStatus(projectId: string) {
    const project = this.projects.get(projectId);
    return project?.getStatus();
  }
}
```

