## 🗄️ Pinia 状态管理设计

### 迭代状态 Store

```typescript
// stores/iterations.ts
import { defineStore } from 'pinia';
import { ref, computed } from 'vue';
import type { Iteration, IterationStatus } from '@/types/iteration';

export const useIterationStore = defineStore('iterations', () => {
  // 状态
  const iterations = ref<Iteration[]>([]);
  const currentIteration = ref<Iteration | null>(null);
  const loading = ref(false);

  // 计算属性
  const completedIterations = computed(() => 
    iterations.value.filter(i => i.status === 'completed')
  );

  const failedIterations = computed(() =>
    iterations.value.filter(i => i.status === 'failed')
  );

  const successRate = computed(() => {
    const total = iterations.value.length;
    if (total === 0) return 0;
    return (completedIterations.value.length / total) * 100;
  });

  // 操作
  async function fetchIterations(params?: any) {
    loading.value = true;
    try {
      const response = await iterationAPI.list(params);
      iterations.value = response.data;
    } finally {
      loading.value = false;
    }
  }

  async function fetchCurrentIteration() {
    const response = await iterationAPI.getCurrent();
    currentIteration.value = response.data;
  }

  function updateIteration(data: Iteration) {
    const index = iterations.value.findIndex(i => i.id === data.id);
    if (index !== -1) {
      iterations.value[index] = data;
    } else {
      iterations.value.unshift(data);
    }
  }

  return {
    iterations,
    currentIteration,
    loading,
    completedIterations,
    failedIterations,
    successRate,
    fetchIterations,
    fetchCurrentIteration,
    updateIteration,
  };
});
```

